import React, { useState } from 'react';

const ContactForm = () => {
  const [formData, setFormData] = useState({
    nombre: '', correo: '', direccion: '', servicio: '', mensaje: ''
  });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    alert(`✉️ Mensaje enviado por ${formData.nombre}. Gracias por contactarnos!`);
  };

  return (
    <section id="contacto" className="contacto">
      <div className="container">
        <div className="section-header">
          <i className="fas fa-paper-plane"></i>
          <h2>Contáctanos</h2>
          <p>Estamos listos para proteger tu organización</p>
        </div>
        <div className="contacto-content">
          <div className="formulario">
            <h3><i className="fas fa-edit"></i> Envíanos un mensaje</h3>
            <form onSubmit={handleSubmit}>
              {['nombre', 'correo', 'direccion'].map((field) => (
                <div className="form-group" key={field}>
                  <label htmlFor={field}>
                    <i className={`fas ${field === 'nombre' ? 'fa-user' : field === 'correo' ? 'fa-envelope' : 'fa-map-marker-alt'}`}></i>
                    {field.charAt(0).toUpperCase() + field.slice(1)}:
                  </label>
                  <input
                    type={field === 'correo' ? 'email' : 'text'}
                    id={field}
                    name={field}
                    placeholder={`Tu ${field}`}
                    value={formData[field]}
                    onChange={handleChange}
                    required={field !== 'direccion'}
                  />
                </div>
              ))}
              <div className="form-group">
                <label htmlFor="servicio"><i className="fas fa-list"></i> Servicio de interés:</label>
                <select id="servicio" name="servicio" value={formData.servicio} onChange={handleChange}>
                  <option value="">Selecciona un servicio</option>
                  <option value="red">Red Team</option>
                  <option value="blue">Blue Team</option>
                  <option value="purple">Purple Team</option>
                  <option value="consultoria">Consultoría TI</option>
                </select>
              </div>
              <div className="form-group">
                <label htmlFor="mensaje"><i className="fas fa-comment"></i> Mensaje:</label>
                <textarea id="mensaje" name="mensaje" rows="5" placeholder="Cuéntanos sobre tu proyecto..." value={formData.mensaje} onChange={handleChange} required></textarea>
              </div>
              <button type="submit" className="btn-submit">
                <i className="fas fa-paper-plane"></i> Enviar Mensaje
              </button>
            </form>
          </div>
          <div className="resultado">
            <h3><i className="fas fa-address-card"></i> Información de Contacto</h3>
            <div className="datos-mostrados">
              {[
                { icon: 'fa-phone-alt', label: 'Teléfono', value: '+591 12345678' },
                { icon: 'fa-envelope', label: 'Correo', value: 'info@blackcatciberseguridad.com' },
                { icon: 'fa-map-marker-alt', label: 'Dirección', value: 'Universidad Autónoma Tomás Frías' },
                { icon: 'fa-clock', label: 'Horario', value: 'Lunes a Viernes: 9:00 - 18:00' }
              ].map((dato, i) => (
                <div className="dato-item" key={i}>
                  <i className={`fas ${dato.icon}`}></i>
                  <div>
                    <strong>{dato.label}:</strong>
                    <span>{dato.value}</span>
                  </div>
                </div>
              ))}
            </div>
            <div className="mapa">
              <iframe
                src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3800.0!2d-65.75!3d-19.58!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x0%3A0x0!2zMTnCsDM0JzQ4LjAiUyA2NcKwNDUnMDAuMCJX!5e0!3m2!1ses!2sbo!4v1600000000000"
                width="100%" height="200" style={{ border: 0 }} allowFullScreen loading="lazy" title="mapa"
              ></iframe>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

export default ContactForm;
